export let moveSpeed = 40;
export let boostMultiplier = 2.5;
export let rotationSpeed = 60;
export let rollSpeed = 45;

let currentVelocity = new THREE.Vector3();
let currentAngularVelocity = new THREE.Vector3();
let lastCamPos = null;

export function onAwake() {
  lastCamPos = null;
}

export function onUpdate(delta) {
  if (!entity.components.Transform) return;
  const shipPos = getEntityPosition(entity.id) || [0, 0, 0];
  const rot = entity.components.Transform.rotation;
  let quaternion;
  if (typeof rigidBody !== 'undefined' && rigidBody) {
    const rbRot = rigidBody.rotation();
    quaternion = new THREE.Quaternion(rbRot.x, rbRot.y, rbRot.z, rbRot.w);
  } else {
    const pitchRad = rot[0] * (Math.PI / 180);
    const yawRad = rot[1] * (Math.PI / 180);
    const rollRad = rot[2] * (Math.PI / 180);
    const euler = new THREE.Euler(pitchRad, yawRad, rollRad, 'YXZ');
    quaternion = new THREE.Quaternion().setFromEuler(euler);
  }
  const forward = new THREE.Vector3(0, 0, 1).applyQuaternion(quaternion);
  const right = new THREE.Vector3(1, 0, 0).applyQuaternion(quaternion);
  const up = new THREE.Vector3(0, 1, 0).applyQuaternion(quaternion);
  let moveX = 0;
  let moveY = 0;
  let moveZ = 0;
  if (Input.getKey("KeyW")) moveZ += 1;
  if (Input.getKey("KeyS")) moveZ -= 1;
  if (Input.getKey("KeyD")) moveX -= 1;
  if (Input.getKey("KeyA")) moveX += 1;
  if (Input.getKey("Space")) moveY += 1;
  if (Input.getKey("ShiftLeft")) moveY -= 1;
  const activeSpeed = Input.getKey("ControlLeft") ? moveSpeed * boostMultiplier : moveSpeed;
  let pitchInput = 0;
  let yawInput = 0;
  let rollInput = 0;
  if (Input.getKey("ArrowUp")) pitchInput -= 1;
  if (Input.getKey("ArrowDown")) pitchInput += 1;
  if (Input.getKey("KeyQ")) yawInput += 1;
  if (Input.getKey("KeyE")) yawInput -= 1;
  if (Input.getKey("ArrowLeft")) rollInput += 1;
  if (Input.getKey("ArrowRight")) rollInput -= 1;
  if (typeof rigidBody !== 'undefined' && rigidBody) {
    const targetVel = new THREE.Vector3().addScaledVector(forward, moveZ * activeSpeed).addScaledVector(right, moveX * (activeSpeed * 0.5)).addScaledVector(up, moveY * (activeSpeed * 0.5));
    currentVelocity.lerp(targetVel, delta * 4);
    rigidBody.setLinvel({ x: currentVelocity.x, y: currentVelocity.y, z: currentVelocity.z }, true);
    const targetAngVel = new THREE.Vector3(pitchInput * (rotationSpeed * Math.PI / 180), yawInput * (rotationSpeed * Math.PI / 180), rollInput * (rollSpeed * Math.PI / 180));
    targetAngVel.applyQuaternion(quaternion);
    currentAngularVelocity.lerp(targetAngVel, delta * 5);
    rigidBody.setAngvel({ x: currentAngularVelocity.x, y: currentAngularVelocity.y, z: currentAngularVelocity.z }, true);
  } else {
    const moveVec = new THREE.Vector3().addScaledVector(forward, moveZ * activeSpeed * delta).addScaledVector(right, moveX * (activeSpeed * 0.5) * delta).addScaledVector(up, moveY * (activeSpeed * 0.5) * delta);
    const newPos = [shipPos[0] + moveVec.x, shipPos[1] + moveVec.y, shipPos[2] + moveVec.z];
    const newRot = [rot[0] + (pitchInput * rotationSpeed * delta), rot[1] + (yawInput * rotationSpeed * delta), rot[2] + (rollInput * rollSpeed * delta)];
    updateComponent(entity.id, 'Transform', { position: newPos, rotation: newRot });
  }
  const mainCam = engine.find("Main Camera");
  if (mainCam) {
    const updatedShipPos = getEntityPosition(entity.id) || shipPos;
    const targetCamPos = new THREE.Vector3().fromArray(updatedShipPos).addScaledVector(forward, -12).addScaledVector(up, 3.5);
    let currentCamPos;
    if (lastCamPos) {
      currentCamPos = lastCamPos.clone().lerp(targetCamPos, delta * 6);
    } else {
      currentCamPos = targetCamPos;
    }
    lastCamPos = currentCamPos.clone();
    const lookTarget = new THREE.Vector3().fromArray(updatedShipPos).addScaledVector(up, 1.0);
    const lookMat = new THREE.Matrix4().lookAt(currentCamPos, lookTarget, up);
    const lookQuat = new THREE.Quaternion().setFromRotationMatrix(lookMat);
    const lookEuler = new THREE.Euler().setFromQuaternion(lookQuat, 'YXZ');
    engine.updateComponent(mainCam.id, 'Transform', {
      position: [currentCamPos.x, currentCamPos.y, currentCamPos.z],
      rotation: [
        lookEuler.x * 180 / Math.PI,
        lookEuler.y * 180 / Math.PI,
        lookEuler.z * 180 / Math.PI
      ]
    });
  }
}
